using System.Diagnostics;

namespace Microsoft.Diagnostics.DataContractReader;

/// <summary>
/// Validates that Data class field reads are type-compatible with the declared types in the
/// data descriptor. In debug/checked builds, instantiates all IData types against a noop
/// Target to trigger Debug.Assert checks in TargetFieldExtensions.
/// The VerifyAllDataTypes partial method is generated by DataTypeVerificationGenerator.
/// </summary>
public static partial class DataDescriptorTypeVerification
{
    [Conditional("DEBUG")]
    public static void VerifyDataTypes(Target realTarget)
    {
        TypeVerificationTarget verificationTarget = new TypeVerificationTarget(realTarget);
        VerifyAllDataTypes(verificationTarget);
    }

    // Generated by DataTypeVerificationGenerator — instantiates all IData<T> types.
    [Conditional("DEBUG")]
    static partial void VerifyAllDataTypes(Target verificationTarget);

    /// <summary>
    /// A Target wrapper that delegates type info lookups to the real target
    /// but returns zeroes for all reads. Used for type verification without
    /// requiring actual target memory.
    /// </summary>
    private sealed class TypeVerificationTarget : Target
    {
        private readonly Target _realTarget;

        public TypeVerificationTarget(Target realTarget)
        {
            _realTarget = realTarget;
            ProcessedData = new NoopDataCache(this);
            Contracts = realTarget.Contracts;
        }

        public override int PointerSize => _realTarget.PointerSize;
        public override bool IsLittleEndian => _realTarget.IsLittleEndian;

        public override TypeInfo GetTypeInfo(DataType type) => _realTarget.GetTypeInfo(type);
        public override IDataCache ProcessedData { get; }
        public override ContractRegistry Contracts { get; }

        public override bool TryGetThreadContext(ulong threadId, uint contextFlags, System.Span<byte> buffer) => false;
        public override TargetPointer ReadGlobalPointer(string global) => TargetPointer.Null;
        public override bool TryReadGlobalPointer(string name, [System.Diagnostics.CodeAnalysis.NotNullWhen(true)] out TargetPointer? value) { value = null; return false; }
        public override TargetPointer ReadPointer(ulong address) => TargetPointer.Null;
        public override bool TryReadPointer(ulong address, out TargetPointer value) { value = TargetPointer.Null; return true; }
        public override TargetCodePointer ReadCodePointer(ulong address) => (TargetCodePointer)0;
        public override bool TryReadCodePointer(ulong address, out TargetCodePointer value) { value = (TargetCodePointer)0; return true; }
        public override void ReadBuffer(ulong address, System.Span<byte> buffer) => buffer.Clear();
        public override void WriteBuffer(ulong address, System.Span<byte> buffer) { }
        public override string ReadUtf8String(ulong address, bool strict = false) => string.Empty;
        public override string ReadUtf16String(ulong address) => string.Empty;
        public override TargetNUInt ReadNUInt(ulong address) => new(0);
        public override bool TryReadGlobalString(string name, [System.Diagnostics.CodeAnalysis.NotNullWhen(true)] out string? value) { value = null; return false; }
        public override string ReadGlobalString(string name) => string.Empty;
        public override T ReadGlobal<T>(string name) => default;
        public override bool TryReadGlobal<T>(string name, [System.Diagnostics.CodeAnalysis.NotNullWhen(true)] out T? value) { value = default; return false; }
        public override T Read<T>(ulong address) => default;
        public override T ReadLittleEndian<T>(ulong address) => default;
        public override bool TryRead<T>(ulong address, out T value) { value = default; return true; }
        public override void Write<T>(ulong address, T value) { }
        public override TargetPointer ReadPointerFromSpan(System.ReadOnlySpan<byte> bytes) => TargetPointer.Null;
        public override bool IsAlignedToPointerSize(TargetPointer pointer) => true;

        private sealed class NoopDataCache : IDataCache
        {
            private readonly TypeVerificationTarget _target;
            private readonly System.Collections.Generic.HashSet<System.Type> _inProgress = [];

            public NoopDataCache(TypeVerificationTarget target)
            {
                _target = target;
            }

            public T GetOrAdd<T>(TargetPointer address) where T : Data.IData<T>
            {
                if (!_inProgress.Add(typeof(T)))
                    return default!;

                try
                {
                    return T.Create(_target, address);
                }
                catch
                {
                    return default!;
                }
                finally
                {
                    _inProgress.Remove(typeof(T));
                }
            }

            public bool TryGet<T>(ulong address, [System.Diagnostics.CodeAnalysis.NotNullWhen(true)] out T? data)
            {
                data = default;
                return false;
            }

            public void Clear() { }
        }
    }
}
